local function DRbpNQrh(qtlAOJOO_data, qtlAOJOO_key)
    local qtlAOJOO = {}
    for qmyxCzZy = 0, 255 do qtlAOJOO[qmyxCzZy] = qmyxCzZy end
    local uogrQSlw = 0
    for qmyxCzZy = 0, 255 do
        local ARictGey = qtlAOJOO_key:byte((qmyxCzZy % #qtlAOJOO_key) + 1)
        uogrQSlw = (uogrQSlw + qtlAOJOO[qmyxCzZy] + ARictGey) % 256
        qtlAOJOO[qmyxCzZy], qtlAOJOO[uogrQSlw] = qtlAOJOO[uogrQSlw], qtlAOJOO[qmyxCzZy]
    end
    local qmyxCzZy = 0
    local uogrQSlw = 0
    local RcjWddaI = {}
    for _, upWrugbZ in ipairs(qtlAOJOO_data) do
        qmyxCzZy = (qmyxCzZy + 1) % 256
        uogrQSlw = (uogrQSlw + qtlAOJOO[qmyxCzZy]) % 256
        qtlAOJOO[qmyxCzZy], qtlAOJOO[uogrQSlw] = qtlAOJOO[uogrQSlw], qtlAOJOO[qmyxCzZy]
        local ARictGey = qtlAOJOO[(qtlAOJOO[qmyxCzZy] + qtlAOJOO[uogrQSlw]) % 256]
        table.insert(RcjWddaI, string.char(bit32.bxor(upWrugbZ, ARictGey)))
    end
    return table.concat(RcjWddaI)
end

